#include <stdio.h>
#include <stdbool.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int a, maxv, first;
        bool all_equal = true;
        for(int i=0;i<N;i++){
            scanf("%d", &a);
            if(i==0){first=a; maxv=a;}
            else{
                if(a!=first) all_equal = false;
                if(a>maxv) maxv=a;
            }
        }
        if(all_equal){
            printf("0\n");
        }else if(a==maxv && N>0 && maxv==a){ // a holds last read value (A[N])
            // check if last element is max
            // we already have maxv, need last element value
            // we stored it in a
            if(a==maxv) printf("1\n");
            else printf("2\n");
        }else{
            // need to know last element value
            // we have it in variable a (last read)
            if(a==maxv) printf("1\n");
            else printf("2\n");
        }
    }
    return 0;
}

