#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        if all(x == arr[0] for x in arr):
            out.append('0')
            continue
        mx = max(arr)
        if arr[-1] == mx:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

